INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('Professional Education','Child and Adolescent Development','medium','Which Piaget stage involves logical thinking but only with concrete objects?','[{"key":"A","text":"Sensorimotor"},{"key":"B","text":"Preoperational"},{"key":"C","text":"Concrete Operational"},{"key":"D","text":"Formal Operational"}]','C','Concrete operational children (7–11) can think logically about tangible, concrete objects but not abstract concepts.','both'),
('Professional Education','Child and Adolescent Development','hard','Gardner''s naturalist intelligence involves:','[{"key":"A","text":"Understanding musical patterns"},{"key":"B","text":"Recognizing and classifying natural objects"},{"key":"C","text":"Logical reasoning"},{"key":"D","text":"Bodily movement and coordination"}]','B','Naturalist intelligence is the ability to recognize and categorize natural objects like plants and animals.','both'),
('Professional Education','Child and Adolescent Development','medium','Bronfenbrenner''s macrosystem refers to:','[{"key":"A","text":"The immediate family setting"},{"key":"B","text":"Cultural values, laws, and customs of society"},{"key":"C","text":"Connections between home and school"},{"key":"D","text":"Settings the child doesn''t directly experience"}]','B','The macrosystem encompasses the overarching cultural, social, and political context that influences all other systems.','both'),
('Professional Education','Child and Adolescent Development','easy','A child who begins to use symbols (words, images) to represent objects is in Piaget''s:','[{"key":"A","text":"Sensorimotor stage"},{"key":"B","text":"Preoperational stage"},{"key":"C","text":"Concrete Operational stage"},{"key":"D","text":"Formal Operational stage"}]','B','Symbolic function — using words and images to represent objects — emerges in the Preoperational stage (2–7 years).','both'),
('Professional Education','Facilitating Learning','easy','Pavlov''s classical conditioning involves learning through:','[{"key":"A","text":"Reward and punishment"},{"key":"B","text":"Association between a neutral stimulus and a natural response"},{"key":"C","text":"Observation and imitation"},{"key":"D","text":"Trial and error"}]','B','Classical conditioning pairs a neutral stimulus with an unconditioned stimulus to elicit a conditioned response.','both'),
('Professional Education','Facilitating Learning','medium','Skinner''s operant conditioning is based on:','[{"key":"A","text":"Association of stimuli"},{"key":"B","text":"Consequences (reinforcement and punishment) shaping behavior"},{"key":"C","text":"Innate biological drives"},{"key":"D","text":"Social observation"}]','B','Operant conditioning holds that behaviors followed by positive consequences are strengthened; those followed by negative consequences are weakened.','both'),
('Professional Education','Facilitating Learning','easy','Positive reinforcement means:','[{"key":"A","text":"Adding a pleasant stimulus to increase a behavior"},{"key":"B","text":"Removing an unpleasant stimulus to increase a behavior"},{"key":"C","text":"Adding an unpleasant stimulus to decrease a behavior"},{"key":"D","text":"Removing a pleasant stimulus to decrease a behavior"}]','A','Positive reinforcement adds a desirable stimulus after a behavior to increase its frequency.','both'),
('Professional Education','Facilitating Learning','medium','Bandura''s social learning theory emphasizes:','[{"key":"A","text":"Conditioning through rewards"},{"key":"B","text":"Learning through observation and modeling"},{"key":"C","text":"Innate cognitive structures"},{"key":"D","text":"Unconscious drives"}]','B','Bandura proposed that people learn by observing others; behavior, environment, and cognition interact (reciprocal determinism).','both'),
('Professional Education','Facilitating Learning','medium','Self-efficacy, according to Bandura, refers to:','[{"key":"A","text":"One''s actual ability to perform a task"},{"key":"B","text":"One''s belief in their ability to succeed at a task"},{"key":"C","text":"Motivation from external rewards"},{"key":"D","text":"Intelligence quotient"}]','B','Self-efficacy is the belief in one''s capability to execute behaviors necessary to achieve specific goals.','both'),
('Professional Education','Facilitating Learning','easy','Bloom''s lowest level of cognitive taxonomy is:','[{"key":"A","text":"Application"},{"key":"B","text":"Analysis"},{"key":"C","text":"Knowledge/Remembering"},{"key":"D","text":"Synthesis"}]','C','The original Bloom''s taxonomy starts with Knowledge; the revised version starts with Remembering.','both'),
('Professional Education','Facilitating Learning','medium','Which level of Bloom''s taxonomy requires students to judge the value of information?','[{"key":"A","text":"Comprehension"},{"key":"B","text":"Application"},{"key":"C","text":"Synthesis"},{"key":"D","text":"Evaluation"}]','D','Evaluation (the highest level) involves making judgments about the value of ideas or materials.','both'),
('Professional Education','Facilitating Learning','medium','Ausubel''s meaningful learning theory states that new learning must be:','[{"key":"A","text":"Based solely on rote memorization"},{"key":"B","text":"Connected to existing knowledge in the learner''s mind"},{"key":"C","text":"Discovered independently by the learner"},{"key":"D","text":"Taught through direct instruction only"}]','B','Ausubel believed new knowledge must be anchored to prior knowledge for meaningful (not rote) learning to occur.','both'),
('Professional Education','Facilitating Learning','medium','Advance organizers, used before teaching new material, serve to:','[{"key":"A","text":"Assess prior knowledge through testing"},{"key":"B","text":"Provide a framework connecting new and existing knowledge"},{"key":"C","text":"Motivate students through rewards"},{"key":"D","text":"Summarize material after a lesson"}]','B','Advance organizers are introductory materials presented at a higher level of abstraction that bridge new and prior learning.','both'),
('Professional Education','Facilitating Learning','medium','Jerome Bruner''s discovery learning involves:','[{"key":"A","text":"Teacher presenting complete, organized content"},{"key":"B","text":"Students constructing knowledge through exploration"},{"key":"C","text":"Rote repetition of facts"},{"key":"D","text":"Behavioral conditioning"}]','B','Bruner advocated for active exploration and discovery as the primary means of constructing knowledge.','both'),
('Professional Education','Facilitating Learning','easy','Metacognition refers to:','[{"key":"A","text":"Learning through memorization"},{"key":"B","text":"Thinking about one''s own thinking and learning processes"},{"key":"C","text":"Imitating a teacher''s behavior"},{"key":"D","text":"Using multiple senses to learn"}]','B','Metacognition is the awareness and regulation of one''s own cognitive processes — "thinking about thinking."','both'),
('Professional Education','Facilitating Learning','hard','Transfer of learning is BEST facilitated when:','[{"key":"A","text":"Students memorize information without understanding"},{"key":"B","text":"There is high similarity between the learning and application contexts"},{"key":"C","text":"Learning is purely theoretical"},{"key":"D","text":"Students compete with each other"}]','B','Transfer is maximized when the conditions of practice are similar to the conditions of application.','both'),
('Professional Education','Facilitating Learning','medium','Constructivism as a learning theory holds that:','[{"key":"A","text":"Knowledge is passively received from teachers"},{"key":"B","text":"Learners actively construct meaning from experiences"},{"key":"C","text":"Learning is primarily a product of reinforcement"},{"key":"D","text":"Intelligence is fixed at birth"}]','B','Constructivism, associated with Piaget and Vygotsky, holds that learners build knowledge through active experience.','both'),
('Professional Education','Facilitating Learning','medium','Which learning theory is associated with "tabula rasa" (blank slate)?','[{"key":"A","text":"Constructivism"},{"key":"B","text":"Humanism"},{"key":"C","text":"Behaviorism"},{"key":"D","text":"Cognitivism"}]','C','Behaviorism views the learner as a blank slate shaped entirely by environmental stimuli and reinforcement.','both'),
('Professional Education','Facilitating Learning','easy','Negative reinforcement involves:','[{"key":"A","text":"Adding a punishment to stop a behavior"},{"key":"B","text":"Removing an aversive stimulus to increase a behavior"},{"key":"C","text":"Ignoring a behavior to reduce it"},{"key":"D","text":"Adding praise to encourage a behavior"}]','B','Negative reinforcement removes something unpleasant when a desired behavior occurs, increasing that behavior.','both'),
('Professional Education','Facilitating Learning','medium','The revised Bloom''s taxonomy (Anderson & Krathwohl) highest level is:','[{"key":"A","text":"Synthesis"},{"key":"B","text":"Evaluation"},{"key":"C","text":"Creating"},{"key":"D","text":"Analyzing"}]','C','The revised taxonomy changed "Synthesis" to "Creating" and moved it to the highest level above Evaluating.','both'),
('Professional Education','Facilitating Learning','medium','Cooperative learning differs from traditional group work because it requires:','[{"key":"A","text":"Individual competition"},{"key":"B","text":"Positive interdependence and individual accountability"},{"key":"C","text":"Teacher-led instruction"},{"key":"D","text":"Homogeneous grouping"}]','B','Cooperative learning requires both positive interdependence (success depends on the group) and individual accountability.','both'),
('Professional Education','Facilitating Learning','hard','Thorndike''s Law of Effect states that:','[{"key":"A","text":"Practice makes perfect"},{"key":"B","text":"Behaviors followed by satisfying consequences are strengthened"},{"key":"C","text":"Organisms learn by observation"},{"key":"D","text":"Repetition alone is sufficient for learning"}]','B','The Law of Effect is the precursor to operant conditioning — behaviors with positive outcomes are repeated; those with negative outcomes are avoided.','both'),
('Professional Education','Facilitating Learning','medium','Intrinsic motivation in learning is best described as:','[{"key":"A","text":"Studying to earn high grades"},{"key":"B","text":"Learning driven by curiosity, interest, and personal satisfaction"},{"key":"C","text":"Performing to please the teacher"},{"key":"D","text":"Motivation from scholarship rewards"}]','B','Intrinsic motivation comes from within the learner — interest, curiosity, and the joy of learning itself.','both'),
('Professional Education','Facilitating Learning','medium','In Gagné''s conditions of learning, the first internal condition required is:','[{"key":"A","text":"Attention"},{"key":"B","text":"Recall of prior learning"},{"key":"C","text":"Motivation and alertness"},{"key":"D","text":"Feedback"}]','C','Gagné''s nine events of instruction begin with gaining the learner''s attention and motivation.','both'),
('Professional Education','Facilitating Learning','easy','Which learning style (VAK) prefers to learn by doing and hands-on activities?','[{"key":"A","text":"Visual"},{"key":"B","text":"Auditory"},{"key":"C","text":"Kinesthetic"},{"key":"D","text":"Linguistic"}]','C','Kinesthetic learners learn best through physical experience, movement, and hands-on activities.','both'),
('Professional Education','Facilitating Learning','medium','Mastery learning (Bloom) holds that:','[{"key":"A","text":"Only gifted students can master all content"},{"key":"B","text":"All students can achieve mastery if given adequate time and instruction"},{"key":"C","text":"Speed of learning determines mastery"},{"key":"D","text":"Content should never be simplified"}]','B','Bloom''s mastery learning proposes that virtually all students can master content if instruction is appropriate and time is sufficient.','both'),
('Professional Education','Facilitating Learning','medium','Problem-based learning (PBL) is characterized by:','[{"key":"A","text":"Teacher presenting solutions directly"},{"key":"B","text":"Students solving complex real-world problems as the starting point"},{"key":"C","text":"Rote memorization of formulas"},{"key":"D","text":"Individual seatwork only"}]','B','PBL uses ill-structured real-world problems as the vehicle for learning, promoting critical thinking and collaboration.','both'),
('Professional Education','Facilitating Learning','hard','The information processing model compares human memory to a computer. Working memory is analogous to:','[{"key":"A","text":"Hard drive storage"},{"key":"B","text":"RAM (active processing space)"},{"key":"C","text":"CPU speed"},{"key":"D","text":"Input devices"}]','B','Working memory (short-term memory) holds information for active processing, similar to computer RAM.','both'),
('Professional Education','Facilitating Learning','medium','Differentiated instruction means:','[{"key":"A","text":"Teaching the same lesson to all students"},{"key":"B","text":"Adjusting content, process, and product based on student needs"},{"key":"C","text":"Grouping only by ability"},{"key":"D","text":"Reducing curriculum content"}]','B','Differentiated instruction tailors teaching strategies, content, and assessments to individual student readiness, interests, and learning profiles.','both'),
('Professional Education','Facilitating Learning','easy','Extinction in operant conditioning occurs when:','[{"key":"A","text":"A behavior is punished repeatedly"},{"key":"B","text":"A reinforced behavior decreases because reinforcement is withheld"},{"key":"C","text":"A new behavior replaces an old one"},{"key":"D","text":"A stimulus is repeatedly presented"}]','B','Extinction is the weakening of a conditioned response when reinforcement is no longer provided.','both'),
('Professional Education','Facilitating Learning','medium','Brain-based learning advocates for:','[{"key":"A","text":"Strict rote memorization"},{"key":"B","text":"Instruction aligned with how the brain naturally learns"},{"key":"C","text":"Punishment-based discipline"},{"key":"D","text":"Single-modality instruction"}]','B','Brain-based learning applies neuroscience research — emotion, patterns, and meaning enhance learning and memory.','both'),
('Professional Education','Facilitating Learning','medium','The jigsaw cooperative learning strategy involves:','[{"key":"A","text":"Each student mastering one piece and teaching it to the group"},{"key":"B","text":"All students doing the same task simultaneously"},{"key":"C","text":"Teacher dividing students by ability"},{"key":"D","text":"Individual competition for rewards"}]','A','In jigsaw, each student becomes an "expert" on one portion of material and teaches it to their home group.','both'),
('Professional Education','Facilitating Learning','hard','Which theorist proposed that intelligence is not fixed and can be developed through effort?','[{"key":"A","text":"Charles Spearman"},{"key":"B","text":"Alfred Binet"},{"key":"C","text":"Carol Dweck (Growth Mindset)"},{"key":"D","text":"Lewis Terman"}]','C','Carol Dweck''s growth mindset theory holds that abilities can be developed through dedication and hard work.','both'),
('Professional Education','Facilitating Learning','medium','Inquiry-based learning is most aligned with which theory?','[{"key":"A","text":"Behaviorism"},{"key":"B","text":"Constructivism"},{"key":"C","text":"Humanism"},{"key":"D","text":"Essentialism"}]','B','Inquiry-based learning, where students explore and construct understanding, aligns with constructivist principles.','both'),
('Professional Education','Facilitating Learning','easy','Which of the following is an example of positive reinforcement in the classroom?','[{"key":"A","text":"Taking away recess for misbehavior"},{"key":"B","text":"Giving a sticker to a student who completes homework"},{"key":"C","text":"Ignoring a student who acts out"},{"key":"D","text":"Removing homework when students behave"}]','B','Giving a sticker (pleasant stimulus) after completing homework (desired behavior) is positive reinforcement.','both'),
('Professional Education','Facilitating Learning','medium','The concept of "flow" in learning, described by Csikszentmihalyi, refers to:','[{"key":"A","text":"Using water tables in science"},{"key":"B","text":"A state of deep, effortless engagement in an appropriately challenging task"},{"key":"C","text":"Group discussion techniques"},{"key":"D","text":"Transitions between lessons"}]','B','Flow is the optimal experience of full immersion and enjoyment in an activity that is challenging yet achievable.','both'),
('Professional Education','Facilitating Learning','hard','Universal Design for Learning (UDL) provides:','[{"key":"A","text":"One standard method of instruction for all"},{"key":"B","text":"Multiple means of representation, engagement, and expression"},{"key":"C","text":"Special education only for disabled students"},{"key":"D","text":"Standardized tests for all learners"}]','B','UDL proactively designs flexible learning materials and activities to accommodate all learners'' variability.','both');
